@@ -410,0 +410,30 @@
+
+  // Compute `known_bits` by shifting known bits of `t1` left and setting the
+  // low `shift` bits to zeros.  Also update the signed and unsigned ranges when
+  // the shift operation does not cause an overflow.
+  template <class CTP>
+  static CTP infer_lshift(CTP t1, int shift) {
+    constexpr int type_bits = sizeof(U<CTP>) * 8;
+    int masked_shift = shift & (type_bits - 1);
+    U<CTP> pattern = (U<CTP>(1) << masked_shift) - U<CTP>(1);
+    U<CTP> known_one_bits = t1->_bits._ones << masked_shift;
+    U<CTP> known_zero_bits = (t1->_bits._zeros << masked_shift) | pattern;
+    KnownBits<U<CTP>> known_bits{known_zero_bits, known_one_bits};
+
+    S<CTP> shifted_slo = S<CTP>(U<CTP>(t1->_lo) << masked_shift);
+    S<CTP> shifted_shi = S<CTP>(U<CTP>(t1->_hi) << masked_shift);
+    bool s_overflow = (shifted_slo >> masked_shift) != t1->_lo ||
+                      (shifted_shi >> masked_shift) != t1->_hi;
+    S<CTP> slo = s_overflow ? std::numeric_limits<S<CTP>>::min() : shifted_slo;
+    S<CTP> shi = s_overflow ? std::numeric_limits<S<CTP>>::max() : shifted_shi;
+
+    U<CTP> shifted_ulo = t1->_ulo << masked_shift;
+    U<CTP> shifted_uhi = t1->_uhi << masked_shift;
+    bool u_overflow = (shifted_ulo >> masked_shift) != t1->_ulo ||
+                      (shifted_uhi >> masked_shift) != t1->_uhi;
+    U<CTP> ulo = u_overflow ? std::numeric_limits<U<CTP>>::min() : shifted_ulo;
+    U<CTP> uhi = u_overflow ? std::numeric_limits<U<CTP>>::max() : shifted_uhi;
+
+    TypeIntPrototype<S<CTP>, U<CTP>> proto{{slo, shi}, {ulo, uhi}, known_bits};
+    return CT<CTP>::make(proto, t1->_widen);
+  }

@@ -626,0 +626,48 @@
+
+// Left shift tests
+template <class U>
+static U lshift_op(U v, int shift) {
+  return v << shift;
+}
+
+// Test correctness: for all values v in input, (v << shift) must be in the result
+template <class InputType>
+static void test_lshift_correctness(const InputType& input, int shift) {
+  using U = std::remove_const_t<decltype(input->_ulo)>;
+  auto result = RangeInference::infer_lshift(input, shift);
+  for (juint v = 0; v <= juint(std::numeric_limits<U>::max()); v++) {
+    if (input.contains(U(v))) {
+      ASSERT_TRUE(result.contains(lshift_op(U(v), shift)));
+    }
+  }
+}
+
+// Test monotonicity: if input is a subset of super, then result is a subset of
+// infer_lshift(super, shift)
+template <class InputType>
+static void test_lshift_monotonicity(const InputType& input, int shift) {
+  auto result = RangeInference::infer_lshift(input, shift);
+  for (const InputType& super : all_instances<InputType>()) {
+    if (super.contains(input)) {
+      ASSERT_TRUE(RangeInference::infer_lshift(super, shift).contains(result));
+    }
+  }
+}
+
+template <class InputType>
+static void test_lshift_for_type() {
+  using U = std::remove_const_t<decltype(InputType::_ulo)>;
+  constexpr int type_bits = sizeof(U) * 8;
+  for (const InputType& input : all_instances<InputType>()) {
+    for (int shift = 0; shift < type_bits; shift++) {
+      test_lshift_correctness(input, shift);
+      test_lshift_monotonicity(input, shift);
+    }
+  }
+}
+
+TEST(opto, range_inference_lshift) {
+  test_lshift_for_type<TypeIntMirror<intn_t<1>, uintn_t<1>>>();
+  test_lshift_for_type<TypeIntMirror<intn_t<2>, uintn_t<2>>>();
+  test_lshift_for_type<TypeIntMirror<intn_t<3>, uintn_t<3>>>();
+}
